		// Token: 0x060010AA RID: 4266 RVA: 0x0041F1F8 File Offset: 0x0041D3F8
		public static void RandomizeWeather()
		{
			Main.numClouds = WorldGen.genRand.Next(10, 200);
			Main.windSpeedCurrent = 0f;
			while (Main.windSpeedCurrent == 0f)
			{
				Main.windSpeedCurrent = WorldGen.genRand.NextFloat() * 0.35f * (float)(WorldGen.genRand.Next(2) * 2 - 1);
				Main.windSpeedTarget = Main.windSpeedCurrent;
			}
			Cloud.resetClouds();
		}

